import { useMemo, useState } from 'react';

type Shot = {
  id: number;
  title: string;
  category: string;
  tone: string;
  location: string;
  image: string;
};

const shots = [
  {
    "id": 1,
    "title": "Afterlight",
    "category": "Editorial",
    "tone": "Warm dusk over the city with a clean, modern colour story.",
    "location": "Late evening feature",
    "image": "https://images.unsplash.com/photo-1492691527719-9d1e07e534b4?auto=format&fit=crop&w=1200&q=80"
  },
  {
    "id": 2,
    "title": "Night Window",
    "category": "Editorial",
    "tone": "Texture, glass, and reflected neon for a sharper brand mood.",
    "location": "Urban study",
    "image": "https://images.unsplash.com/photo-1499364615650-ec38552f4f34?auto=format&fit=crop&w=1200&q=80"
  },
  {
    "id": 3,
    "title": "Rooftop Study",
    "category": "Portrait",
    "tone": "Soft directional light and calm posture without visual noise.",
    "location": "City rooftop",
    "image": "https://images.unsplash.com/photo-1521119989659-a83eee488004?auto=format&fit=crop&w=1200&q=80"
  },
  {
    "id": 4,
    "title": "Morning Run",
    "category": "Lifestyle",
    "tone": "Motion, distance, and enough atmosphere to keep the frame alive.",
    "location": "Early movement",
    "image": "https://images.unsplash.com/photo-1517832606299-7ae9b720a186?auto=format&fit=crop&w=1200&q=80"
  },
  {
    "id": 5,
    "title": "Borrowed Blue",
    "category": "Campaign",
    "tone": "Clean composition with a cool palette and restrained styling.",
    "location": "Product feature",
    "image": "https://images.unsplash.com/photo-1516035069371-29a1b244cc32?auto=format&fit=crop&w=1200&q=80"
  },
  {
    "id": 6,
    "title": "Paper Studio",
    "category": "Still life",
    "tone": "Minimal shapes, tactile surfaces, and deliberate spacing.",
    "location": "Studio set",
    "image": "https://images.unsplash.com/photo-1519389950473-47ba0277781c?auto=format&fit=crop&w=1200&q=80"
  }
] satisfies Shot[];
const metaItems = ["Editorial direction","Portrait rhythm","Campaign polish","Modern booking flow"];

export default function App() {
  const [activeId, setActiveId] = useState(shots[0].id);
  const activeShot = useMemo(() => shots.find((shot) => shot.id === activeId) ?? shots[0], [activeId]);
  const scrollToId = (id: string) => document.getElementById(id)?.scrollIntoView({ behavior: 'smooth', block: 'start' });

  return (
    <main className="portfolio-shell">
      <section className="hero-card">
        <div className="hero-copy">
          <p className="eyebrow">Photography portfolio</p>
          <h1>Images that feel composed, tactile, and ready to be remembered.</h1>
          <p className="lede">Editorial photography for people, spaces, and campaigns that need mood, clarity, and a strong sense of place.</p>
          <div className="hero-actions">
            <button type="button" className="primary" onClick={() => scrollToId('contact')}>Book a session</button>
            <button type="button" className="secondary" onClick={() => scrollToId('gallery')}>View selected work</button>
          </div>
        </div>
        <aside className="hero-note">
          <span>Selected frame</span>
          <strong>{activeShot.title}</strong>
          <p>{activeShot.tone}</p>
          <small>{activeShot.location}</small>
        </aside>
      </section>

      <section className="meta-strip">
        {metaItems.map((item) => (
          <span key={item}>{item}</span>
        ))}
      </section>

      <section id="gallery" className="gallery-shell">
        <div className="section-heading">
          <p className="eyebrow">Masonry gallery</p>
          <h2>Gallery built for browsing</h2>
        </div>
        <div className="gallery-grid">
          {shots.map((shot, index) => (
            <button
              key={shot.id}
              type="button"
              className={`gallery-card ${activeId === shot.id ? "is-active" : ""}`}
              onClick={() => setActiveId(shot.id)}
              style={{ animationDelay: `${index * 65}ms` }}
            >
              <div className="image-fill">
                <img src={shot.image} alt={shot.title} loading={index < 2 ? "eager" : "lazy"} />
              </div>
              <div className="card-copy">
                <span>{shot.category}</span>
                <strong>{shot.title}</strong>
                <p>{shot.tone}</p>
                <small>{shot.location}</small>
              </div>
            </button>
          ))}
        </div>
      </section>

      <section className="lightbox-shell">
        <div className="lightbox-frame">
          <div className="lightbox-image">
            <img src={activeShot.image} alt={activeShot.title} />
          </div>
          <div className="lightbox-copy">
            <p className="eyebrow">Fullscreen lightbox</p>
            <h2>{activeShot.title}</h2>
            <p>{activeShot.tone}</p>
            <div className="lightbox-row">
              <span>{activeShot.category}</span>
              <span>{activeShot.location}</span>
              <span>Licensing-ready delivery</span>
            </div>
          </div>
        </div>
      </section>

      <section id="contact" className="contact-shell">
        <p className="eyebrow">Photography portfolio</p>
        <h2>Start a photography brief</h2>
        <p className="contact-lede">Available for editorial, portrait, and campaign work with a polished, modern visual direction.</p>
        <div className="contact-points">
        <span>Editorial + campaign shoots</span>
        <span>Fast shortlist + planning</span>
        <span>Licensing-ready delivery</span>
        </div>
        <a className="inline-link" href="mailto:hello@example.com?subject=Photography%20session">Send an enquiry</a>
      </section>
    </main>
  );
}
